using namespace std;

int main(int argc, char *argv[]) {
    int board[1200][1200] = {0};
    int W, H, N, X, Y, choice, amount = 0;
    cin >> W >> H >> N;

    for (int i = 1; i <= H; ++i) {
        for (int j = 1; j <= W; ++j) {
            board[i][j] = 1;
        }
    }

    for (int repeat = 0; repeat < N; ++repeat) {
        cin >> X >> Y >> choice;
        if (choice == 1) {
            for (int j = 1; j <= X; ++j) {
                for (int i = 1; i <= H; ++i) {
                    board[i][j] += 1;
                }
            }
        } else if (choice == 2) {
            for (int j = W; j > X; --j) {
                for (int i = 1; i <= H; ++i) {
                    board[i][j] += 1;
                }
            }
        } else if (choice == 3) {
            for (int i = 1; i <= Y; ++i) {
                for (int j = 1; j <= W; ++j) {
                    board[i][j] += 1;
                }
            }
        } else if (choice == 4) {
            for (int i = H; i > Y; --i) {
                for (int j = 1; j <= W; ++j) {
                    board[i][j] += 1;
                }
            }
        }
    }

    for (int i = 1; i <= H; ++i) {
        for (int j = 1; j <= W; ++j) {
            if (board[i][j] == 1) {
                ++amount;
            }
        }
    }

    cout << amount << endl;
}

