	int l = 1, r = n, res;

	while (l <= r) {

		int mid = l + r >> 1;

		if (check(b[mid]))	l = mid + 1, res = mid;

		else r = mid - 1;

	}

	return b[res];

}



int main() {



	scanf("%d", &n);

	n = n * 2 - 1;

	for (int i = 1; i <= n; ++i)	scanf("%d", a + i);

	for (int i = 1; i <= n; ++i)	b[i] = a[i];



	sort(b + 1, b + n + 1);



	printf("%d\n", solve());	



	return 0;

}
